import pymysql
import logging
import json
# 濡쒓퉭 ?ㅼ젙
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')


def connect_db(config):
    """ ?곗씠?곕쿋?댁뒪 ?곌껐 ?⑥닔 """
    try:
        connection = pymysql.connect(host=config['host'],
                                     user=config['user'],
                                     password=config['password'],
                                     database=config['database'],
                                     cursorclass=pymysql.cursors.DictCursor)
        logging.info("Database connection successful")
        return connection
    except Exception as e:
        logging.error(f"Database connection failed: {e}")
        return None


def insert_data(connection, image_list):
    """ ?곗씠???쎌엯 ?⑥닔 """
    with connection.cursor() as cursor:
        for image in image_list:
            try:
                url = image[0]
                title = image[1]
                author = image[2]
                description = image[3]
                emotions = ','.join(str(e) for e in image[4])
                color_cluster_ratio = json.dumps(image[5])
                # cluster_rgb = ','.join(['({},{},{})'.format(*c[1]) for c in image[5] if len(c[1]) == 3])
                # cluster_ratio = ','.join([str(c[2]) for c in image[5]])
                # cluster_count = ','.join([str(c[3]) for c in image[5]])
                main_color_1 = max(image[5], key=lambda x: x[3])  # ?대윭?ㅽ꽣 移댁슫?멸? 媛?????됱긽???좏깮
                main_color = main_color_1[0]
                sql = """
                INSERT INTO images (url, title, author, description, emotions, color_cluster_ratio, main_color)
                VALUES (%s, %s, %s, %s, %s, %s, %s)
                """
                cursor.execute(sql, (
                url, title, author, description, emotions, color_cluster_ratio, main_color))
                logging.info(f"Data inserted successfully for image: {title}")
            except Exception as e:
                logging.error(f"Failed to insert data for image: {title}, Error: {e}")

        connection.commit()
        logging.info("All data committed successfully")


